import React from 'react';
import { ScrollView } from 'react-native';
import type { Meta, StoryObj } from '@storybook/react';
import {
  Accordion,
  Box,
  Button,
  Header,
  Icon,
  Text,
} from '@semparar/design-system-app';
import { NavigationDecorator } from '../../.storybook/decorators/NavigationDecorator';

interface FaqItem {
  id: number;
  title: string;
  text: string;
  titleColor: 'BRAND_COMPLEMENT_01';
  headerIconName: string;
  hasSecondaryParagraph: boolean;
  hideSecondaryIconParagraph: boolean;
  hideIcon: boolean;
  onPressCard?: () => void;
}

const MOCK_FAQ_CATEGORIES = {
  'Como funciona': {
    icon: 'icon-help-circle',
    questions: [
      {
        question: 'O que é o programa de pontos Sem Parar?',
        answer:
          'O programa de pontos Sem Parar é um benefício exclusivo para clientes Sem Parar Mais. Você acumula pontos automaticamente ao usar seus produtos e pode trocar por descontos em abastecimento, estacionamento, seguro auto e muito mais.',
      },
      {
        question: 'Como acumulo pontos?',
        answer:
          'Você acumula pontos automaticamente a cada passagem em pedágios, estacionamentos e ao usar os serviços Sem Parar. A quantidade de pontos varia de acordo com o valor da transação e o seu plano.',
      },
      {
        question: 'Os pontos expiram?',
        answer:
          'Sim, os pontos têm validade de 12 meses a partir da data de acúmulo. Fique atento ao extrato para aproveitar seus pontos antes do vencimento.',
      },
      {
        question: 'Como verifico meu saldo de pontos?',
        answer:
          'Você pode verificar seu saldo de pontos diretamente no app Sem Parar, na seção "Pontos". Lá você encontra o saldo disponível, pontos a liberar e o extrato completo.',
      },
    ],
  },
  'Vouchers': {
    icon: 'icon-tag',
    questions: [
      {
        question: 'O que é um voucher?',
        answer:
          'Um voucher é um crédito de desconto que você cria usando seus pontos. Ele pode ser usado em abastecimento, estacionamento ou outros serviços parceiros.',
      },
      {
        question: 'Como criar um voucher?',
        answer:
          'Na tela de pontos, toque em "Criar voucher", escolha o tipo de desconto desejado, defina o valor em pontos e confirme. O voucher será criado e ficará disponível na seção "Meus Vouchers".',
      },
      {
        question: 'Posso usar o voucher mais de uma vez?',
        answer:
          'Sim! O voucher pode ser usado parcialmente. Por exemplo, se você criar um voucher de R$ 50,00 e usar R$ 30,00 em um abastecimento, os R$ 20,00 restantes ficam disponíveis para uso futuro.',
      },
    ],
  },
  'Cashback na fatura': {
    icon: 'icon-payment-invoice',
    questions: [
      {
        question: 'Como funciona o cashback na fatura?',
        answer:
          'O cashback na fatura permite que você use seus pontos para obter desconto diretamente na sua fatura Sem Parar. Você define quanto quer converter e o desconto é aplicado automaticamente.',
      },
      {
        question: 'Quanto tempo demora para o cashback ser aplicado?',
        answer:
          'O cashback é processado e aplicado na sua fatura em até 72 horas úteis após a confirmação.',
      },
      {
        question: 'Tem valor mínimo para o cashback?',
        answer:
          'Sim, o valor mínimo para resgate de cashback na fatura é de 500 pontos. A conversão segue a tabela vigente do programa.',
      },
    ],
  },
};

function buildFaqItems(
  categoryName: string,
): FaqItem[] {
  const category = MOCK_FAQ_CATEGORIES[categoryName as keyof typeof MOCK_FAQ_CATEGORIES];
  if (!category) return [];

  return category.questions.map((item, index) => ({
    id: index,
    title: item.question,
    text: item.answer,
    titleColor: 'BRAND_COMPLEMENT_01' as const,
    headerIconName: category.icon,
    hasSecondaryParagraph: false,
    hideSecondaryIconParagraph: true,
    hideIcon: true,
    onPressCard: () => {},
  }));
}

function ErrorState({ onRetry }: { onRetry: () => void }) {
  return (
    <Box flex={1} justify="center" align="center" pd="innerLarge">
      <Icon name="icon-circle-alert" color="DENY_COLOR_01" size={48} />
      <Text type="paragraphXXXL" align="center" mt="smaller" mb="xxxs">
        Ops, algo deu errado...
      </Text>
      <Text
        type="paragraphMD"
        align="center"
        color="INTENSE_COLOR_05"
        mb="smaller"
      >
        Não foi possível carregar as informações. Por favor, tente novamente.
      </Text>
      <Button text="Tentar novamente" onPress={onRetry} />
    </Box>
  );
}

function LearnMoreWrapper({
  category = 'Como funciona',
  hasError = false,
}: {
  category?: string;
  hasError?: boolean;
}) {
  const items = buildFaqItems(category);
  const title = category;

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
      <Header
        title="Saiba mais"
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
        isOption={false}
      />
      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
        {hasError ? (
          <ErrorState onRetry={() => {}} />
        ) : (
          <Box mr="xs" ml="xs" mt="small">
            <Text type="subtitleXXLB" color="NEUTRAL_DARK_01" mb="small">
              {title}
            </Text>
            <Accordion
              items={items}
              title={title}
              iconSeeLess="icon-up"
              iconSeeMore="icon-down"
              iconColor="BRAND_BASE_01"
              isMap
              version="2.0"
            />
          </Box>
        )}
      </ScrollView>
    </Box>
  );
}

const meta: Meta<typeof LearnMoreWrapper> = {
  title: 'Screens/LearnMoreRewardProgram',
  component: LearnMoreWrapper,
  decorators: [NavigationDecorator],
  argTypes: {
    category: {
      control: { type: 'select' },
      options: Object.keys(MOCK_FAQ_CATEGORIES),
      description: 'FAQ category to display',
    },
    hasError: {
      control: { type: 'boolean' },
      description: 'API error state',
    },
  },
};

export default meta;
